  7→// A example of static library loading in IREE. See the README.md for more info.
  8→// Note: this demo requires artifacts from iree-compile before it will run.
  9→
 10→#include <float.h>
 11→#include <math.h>
 12→#include "iree/base/alignment.h"
 13→#include "iree/base/config.h"
 14→#include "iree/hal/local/loaders/static_library_loader.h"
 15→#include "iree/hal/drivers/local_sync/sync_device.h"
 16→#include "iree/modules/hal/module.h"
 17→#include "iree/runtime/api.h"
 18→#include "iree/vm/api.h"
 19→#include <stddef.h>
 20→#include "host-c.h"
 21→#include <stdint.h>
 22→#include <time.h>
 23→
 24→#ifdef PF_COUNTER
 25→#include "nds32_pfcounter.h"
 26→#endif
 27→
 28→#ifdef __cplusplus
 29→extern "C" {
 30→#endif  //  __cplusplus
 31→iree_status_t module_create(iree_vm_instance_t* v1, iree_allocator_t v2,
 32→                               iree_vm_module_t** v3);
 33→#ifdef __cplusplus
 34→}  // extern "C"
 35→#endif  //  __cplusplus
 36→
 37→extern const iree_hal_executable_library_header_t**
 38→QUERY(
 39→    iree_hal_executable_library_version_t max_version,
 40→    const iree_hal_executable_environment_v0_t* environment);
 41→
 42→
 43→iree_status_t create_module(iree_vm_instance_t* instance, iree_vm_module_t** module) {
 44→  return module_create(instance, iree_vm_instance_allocator(instance), module);
 45→}
 46→
 47→void print_success() { printf("static_library_run_c passed\n"); }
 48→// A function to create the HAL device from the different backend targets.
 49→// The HAL device is returned based on the implementation, and it must be
 50→// released by the caller.
 51→iree_status_t create_device_with_static_loader(iree_allocator_t host_allocator,
 52→                                               iree_hal_device_t** out_device) {
 53→  // Set paramters for the device created in the next step.
 54→  iree_hal_sync_device_params_t params;
 55→  iree_hal_sync_device_params_initialize(&params);
 56→
 57→  // Register the statically linked executable library.
 58→  const iree_hal_executable_library_query_fn_t libraries[] = {
 59→      QUERY,
 60→  };
 61→  iree_hal_executable_loader_t* library_loader = NULL;
 62→  iree_status_t status = iree_hal_static_library_loader_create(
 63→      IREE_ARRAYSIZE(libraries), libraries,
 64→      iree_hal_executable_import_provider_null(), host_allocator,
 65→      &library_loader);
 66→
 67→  // Use the default host allocator for buffer allocations.
 68→  iree_string_view_t identifier = iree_make_cstring_view("local-sync");
 69→  iree_hal_allocator_t* device_allocator = NULL;
 70→  if (iree_status_is_ok(status)) {
 71→    status = iree_hal_allocator_create_heap(identifier, host_allocator,
 72→                                            host_allocator, &device_allocator);
 73→  }
 74→
 75→  // Create the device and release the executor and loader afterwards.
 76→  if (iree_status_is_ok(status)) {
 77→    status = iree_hal_sync_device_create(
 78→        identifier, &params, /*loader_count=*/1, &library_loader,
 79→        device_allocator, host_allocator, out_device);
 80→  }
 81→
 82→  iree_hal_allocator_release(device_allocator);
 83→  iree_hal_executable_loader_release(library_loader);
 84→  return status;
 85→}
 86→
 87→iree_status_t Run() {
 88→  iree_status_t status = iree_ok_status();
 89→
 90→  iree_runtime_instance_options_t instance_options;
 91→  iree_runtime_instance_options_initialize(&instance_options);
 92→  iree_runtime_instance_options_use_all_available_drivers(&instance_options);
 93→  iree_runtime_instance_t* instance = NULL;
 94→
 95→  IREE_RETURN_IF_ERROR(
 96→    iree_runtime_instance_create(&instance_options,
 97→                                          iree_allocator_system(), &instance), " instance create");
 98→
 99→  // Create dylib device with static loader.
100→  iree_hal_device_t* device = NULL;
101→  IREE_RETURN_IF_ERROR(
102→    create_device_with_static_loader(iree_allocator_system(), &device), "create device");
103→
104→  // Session configuration (one per loaded module to hold module state).
105→  iree_runtime_session_options_t session_options;
106→  iree_runtime_session_options_initialize(&session_options);
107→  iree_runtime_session_t* session = NULL;
108→  if (iree_status_is_ok(status)) {
109→    status = iree_runtime_session_create_with_device(
110→        instance, &session_options, device,
111→        iree_runtime_instance_host_allocator(instance), &session);
112→  }
113→
114→  // Load bytecode module from the embedded data. Append to the session.
115→  iree_vm_module_t* module = NULL;
116→
117→  IREE_RETURN_IF_ERROR(
118→    create_module(iree_runtime_instance_vm_instance(instance), &module), "create module");
119→
120→  IREE_RETURN_IF_ERROR(
121→    iree_runtime_session_append_module(session, module),
122→    "session append module");
123→
124→  // Lookup the entry point function call.
125→  const char kMainFunctionName[] = _FUNC;
126→  iree_runtime_call_t call;
127→  memset(&call, 0, sizeof(call));
128→  IREE_RETURN_IF_ERROR(
129→    iree_runtime_call_initialize_by_name(
130→        session, iree_make_cstring_view(kMainFunctionName), &call),
131→    "init call");
132→
133→  iree_vm_list_t* inputs;
134→  IREE_CHECK_OK(iree_vm_list_create(iree_vm_make_value_type_def(IREE_VM_VALUE_TYPE_I32), 1,
135→                                    iree_allocator_system(), &inputs));
136→  iree_vm_value_t arg_value = iree_vm_value_make_i32(1);
137→  IREE_RETURN_IF_ERROR(iree_vm_list_push_value(inputs, &arg_value));
138→
139→  iree_vm_list_t* outputs = NULL;
140→  IREE_CHECK_OK(iree_vm_list_create(iree_vm_make_value_type_def(IREE_VM_VALUE_TYPE_I32), 1,
141→                                    iree_allocator_system(), &outputs));
142→
143→  printf("tune...ok\n");
144→#ifdef PF_COUNTER
145→    startPFM;
146→#endif
147→  IREE_CHECK_OK(
148→      iree_runtime_session_call_by_name(session, iree_make_cstring_view(kMainFunctionName), inputs, outputs));
149→#ifdef PF_COUNTER
150→    stopPFM;
151→    readResult();
152→#endif
153→  printf(" PASS1 \n");
154→  iree_runtime_call_deinitialize(&call);
155→
156→  // Cleanup session and instance.
157→  iree_hal_device_release(device);
158→  iree_runtime_session_release(session);
159→  iree_runtime_instance_release(instance);
160→  iree_vm_module_release(module);
161→
162→  return status;
163→}
164→
165→int main(int argc, char** argv) {
166→  __asm__ __volatile__ ( " csrs mstatus,  %0" :: "r"((unsigned long) 1 << 9) );
167→
168→  iree_status_t result = Run();
169→  if (!iree_status_is_ok(result)) {
170→    iree_status_fprint(stderr, result);
171→    iree_status_ignore(result);
172→    return -1;
173→  }
174→  iree_status_ignore(result);
175→  return 0;
176→}
